import React, { useState } from "react";

export default function InterestCalculatorPanel() {
  const [principal, setPrincipal] = useState(100000);
  const [rate, setRate] = useState(3);
  const [period, setPeriod] = useState(10);

  const totalPayable = (principal * rate * period) / 100;

  return (
    <section
      style={{
        background: "#F5F7FB",
        borderRadius: 20,
        boxShadow: "0 2px 8px #7286D311",
        padding: "2rem",
        margin: "2rem 0",
      }}
    >
      <h2
        style={{
          color: "#5D5FEF",
          fontWeight: 700,
          fontSize: 28,
          marginBottom: 18,
        }}
      >
        Interest Calculator
      </h2>
      <div style={{ display: "flex", gap: 24, marginBottom: 24 }}>
        <div>
          <label style={{ color: "#888", fontSize: 14 }}>Primary amount</label>
          <input
            type="number"
            value={principal}
            onChange={(e) => setPrincipal(Number(e.target.value))}
            style={{
              display: "block",
              width: 140,
              padding: 10,
              borderRadius: 6,
              border: "1px solid #CCC",
              background: "#fff",
              fontSize: 16,
              marginTop: 4,
            }}
          />
        </div>
        <div>
          <label style={{ color: "#888", fontSize: 14 }}>Interest %</label>
          <input
            type="number"
            value={rate}
            onChange={(e) => setRate(Number(e.target.value))}
            style={{
              display: "block",
              width: 140,
              padding: 10,
              borderRadius: 6,
              border: "1px solid #CCC",
              background: "#fff",
              fontSize: 16,
              marginTop: 4,
            }}
          />
        </div>
        <div>
          <label style={{ color: "#888", fontSize: 14 }}>Period (months)</label>
          <input
            type="number"
            value={period}
            onChange={(e) => setPeriod(Number(e.target.value))}
            style={{
              display: "block",
              width: 140,
              padding: 10,
              borderRadius: 6,
              border: "1px solid #CCC",
              background: "#fff",
              fontSize: 16,
              marginTop: 4,
            }}
          />
        </div>
      </div>
      <div style={{ fontSize: 16, color: "#222", marginBottom: 10 }}>
        <strong>Total payable:</strong>{" "}
        <span style={{ color: "#5D5FEF" }}>
          ₹ {totalPayable.toLocaleString()}
        </span>
      </div>
      <div style={{ fontSize: 13, color: "#888" }}>
        Total period: {period} months ( ₹ {(totalPayable / period).toFixed(2)} /
        month )
      </div>
    </section>
  );
}
